 1	import React, { FC, memo } from 'react';
 2	
 3	import { modelToGroupVersionKind, ProjectModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import InlineFilterSelect from '@kubevirt-utils/components/FilterSelect/InlineFilterSelect';
 5	import { ALL_PROJECTS } from '@kubevirt-utils/hooks/constants';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getName } from '@kubevirt-utils/resources/shared';
 8	import { K8sResourceCommon, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Text, TextVariants } from '@patternfly/react-core';
10	
11	import './TemplatesCatalogProjectsDropdown.scss';
12	
13	type TemplatesCatalogProjectsDropdownProps = {
14	  onChange: (project: string) => void;
15	  selectedProject: string;
16	};
17	
18	export const TemplatesCatalogProjectsDropdown: FC<TemplatesCatalogProjectsDropdownProps> = memo(
19	  ({ onChange, selectedProject }) => {
20	    const { t } = useKubevirtTranslation();
21	    const [projects] = useK8sWatchResource<K8sResourceCommon[]>({
22	      groupVersionKind: modelToGroupVersionKind(ProjectModel),
23	      isList: true,
24	      namespaced: false,
25	    });
26	
27	    const onSelect = (value: string) => {
28	      onChange(value === ALL_PROJECTS ? '' : value);
29	    };
30	
31	    return (
32	      <div className="templates-catalog-project-dropdown">
33	        <Text className="templates-catalog-project-dropdown-label" component={TextVariants.h6}>
34	          {t('Template project')}
35	        </Text>
36	        <InlineFilterSelect
37	          options={[
38	            { children: ALL_PROJECTS, value: ALL_PROJECTS },
39	            ...projects
40	              .sort((a, b) => getName(a).localeCompare(getName(b)))
41	              .map((proj) => {
42	                const name = getName(proj);
43	                return { children: name, value: name };
44	              }),
45	          ]}
46	          selected={selectedProject || ALL_PROJECTS}
47	          setSelected={onSelect}
48	          toggleProps={{ isFullWidth: true }}
49	        />
50	      </div>
51	    );
52	  },
53	);
54	
55	TemplatesCatalogProjectsDropdown.displayName = 'TemplatesCatalogProjectsDropdown';

